export const CC_ROSTER: RosterMember[] = [...CC_FULL_MEMBERS, ...CC_ALTERNATE_MEMBERS];

export function rosterForNode(nodeId: string): RosterMember[] | null {
  if (nodeId === "cc") return CC_ROSTER;
  if (nodeId === "nc") return NC_DELEGATES;
  return null;
}
